SQL:
SELECT SUM(`ActualCost`) - SUM(`PlannedCost`) AS difference
FROM `WorkOrderRouting`
WHERE `ProductID` = 818;

SELECT
  (SELECT COUNT(DISTINCT `Order ID`) FROM east_superstore  WHERE strftime('%Y', `Order Date`) = '2015') AS east_orders,
  (SELECT COUNT(DISTINCT `Order ID`) FROM west_superstore  WHERE strftime('%Y', `Order Date`) = '2015') AS west_orders;

SELECT `ranking_criteria_id`, `score`
FROM `university_ranking_year`
WHERE `university_id` = 68 AND `year` = 2015;

SELECT SUM(`stars` * `votes`) * 1.0 / SUM(`votes`) AS average_stars
FROM `Vote`
WHERE `episode_id` = (
        SELECT `episode_id` FROM `Episode`
        WHERE `title` = 'Wedding for Disaster'
);

SELECT c.`Name`
FROM `City` AS c
JOIN `Country` AS co ON c.`CountryCode` = co.`Code`
WHERE co.`LifeExpectancy` = (
        SELECT MAX(`LifeExpectancy`) FROM `Country`
);

SELECT `ContactName`
FROM `Suppliers`
WHERE `SupplierName` = 'Heli Süßwaren GmbH & Co. KG';

SELECT COUNT(*)
FROM establishment
WHERE risk_level = (SELECT MAX(risk_level) FROM establishment);

SELECT COUNT(*)
FROM Menu
WHERE sponsor = 'PACIFIC MAIL STEAMSHIP COMPANY' AND page_count <= 2;

SELECT AVG(`VacationHours`) AS avg_vacation_hours
FROM `Employee`
WHERE `Gender` = 'M';

SELECT COUNT(DISTINCT COALESCE(`playerID`, `firstName` || ' ' || `lastName`)) AS num_joe_players
FROM `draft`
WHERE `firstName` = 'Joe' AND `draftYear` = 1970;
